/**
 * Media Module Types
 *
 * Type definitions for the Media module including:
 * - Media entity types
 * - Upload DTOs
 * - Processing options
 * - Event payloads
 * - Query filters
 *
 * @module modules/_core/media/types
 *
 * @example
 * ```typescript
 * import type {
 *   Media,
 *   UploadMediaRequest,
 *   MediaListParams,
 * } from '@/modules/_core/media/media.types';
 *
 * async function uploadFile(data: UploadMediaRequest): Promise<Media> { ... }
 * ```
 */

import type { MediaType, MediaStorage } from '@prisma/client';

// -----------------------------------------------------------------------------
// Core Entity Types
// -----------------------------------------------------------------------------

/**
 * Media entity from Prisma
 */
export interface Media {
  /** Unique identifier (CUID) */
  id: string;
  /** Organization ID (tenant) */
  organizationId: string;
  /** Stored filename */
  filename: string;
  /** Original filename from upload */
  originalName: string;
  /** MIME type (e.g., image/jpeg) */
  mimeType: string;
  /** File size in bytes */
  size: number;
  /** Media type (IMAGE, VIDEO, DOCUMENT) */
  type: MediaType;
  /** Storage location (LOCAL, S3, CDN) */
  storage: MediaStorage;
  /** Public URL to access the file */
  url: string;
  /** Thumbnail URL (for images/videos) */
  thumbnailUrl: string | null;
  /** Alt text for accessibility */
  alt: string | null;
  /** Additional metadata (JSON) */
  metadata: MediaMetadata;
  /** Creation timestamp */
  createdAt: Date;
  /** Last update timestamp */
  updatedAt: Date;
  /** Soft delete timestamp */
  deletedAt: Date | null;
}

/**
 * Media with related organization data
 */
export interface MediaWithRelations extends Media {
  /** Associated organization */
  organization?: {
    id: string;
    name: string;
    slug: string;
  };
}

// -----------------------------------------------------------------------------
// Metadata Types
// -----------------------------------------------------------------------------

/**
 * Media metadata structure
 */
export interface MediaMetadata {
  /** Image dimensions */
  dimensions?: ImageDimensions;
  /** Video information */
  video?: VideoMetadata;
  /** Processing information */
  processing?: ProcessingMetadata;
  /** Custom tags */
  tags?: string[];
  /** Upload source */
  source?: string;
  /** User who uploaded */
  uploadedBy?: string;
}

/**
 * Image dimensions
 */
export interface ImageDimensions {
  /** Width in pixels */
  width: number;
  /** Height in pixels */
  height: number;
  /** Aspect ratio */
  aspectRatio?: number;
}

/**
 * Video metadata
 */
export interface VideoMetadata {
  /** Duration in seconds */
  duration?: number;
  /** Video codec */
  codec?: string;
  /** Frame rate */
  frameRate?: number;
  /** Bitrate in kbps */
  bitrate?: number;
}

/**
 * Processing metadata
 */
export interface ProcessingMetadata {
  /** Whether image has been processed */
  processed: boolean;
  /** Original file size before optimization */
  originalSize?: number;
  /** Compression ratio achieved */
  compressionRatio?: number;
  /** Generated variants */
  variants?: MediaVariant[];
}

/**
 * Media variant (thumbnail, resize)
 */
export interface MediaVariant {
  /** Variant name (e.g., 'thumbnail', 'medium') */
  name: string;
  /** Variant URL */
  url: string;
  /** Width in pixels */
  width: number;
  /** Height in pixels */
  height: number;
  /** File size in bytes */
  size: number;
}

// -----------------------------------------------------------------------------
// Request/Response Types
// -----------------------------------------------------------------------------

/**
 * Upload media request
 */
export interface UploadMediaRequest {
  /** Original filename */
  originalName: string;
  /** MIME type */
  mimeType: string;
  /** File size in bytes */
  size: number;
  /** File buffer or stream */
  buffer?: Buffer;
  /** Alt text (optional) */
  alt?: string;
  /** Custom tags (optional) */
  tags?: string[];
  /** Auto-generate thumbnail */
  generateThumbnail?: boolean;
  /** Auto-optimize image */
  optimize?: boolean;
}

/**
 * Upload media response
 */
export interface UploadMediaResponse {
  /** Uploaded media */
  media: Media;
  /** Upload success message */
  message: string;
}

/**
 * Upload multiple media request
 */
export interface UploadMultipleMediaRequest {
  /** Array of files to upload */
  files: UploadMediaRequest[];
}

/**
 * Upload multiple media response
 */
export interface UploadMultipleMediaResponse {
  /** Array of uploaded media */
  media: Media[];
  /** Number of successful uploads */
  successful: number;
  /** Number of failed uploads */
  failed: number;
  /** Error details for failed uploads */
  errors?: UploadError[];
}

/**
 * Upload error details
 */
export interface UploadError {
  /** Original filename */
  filename: string;
  /** Error message */
  message: string;
  /** Error code */
  code: string;
}

/**
 * Update media request
 */
export interface UpdateMediaRequest {
  /** Alt text */
  alt?: string | null;
  /** Custom tags */
  tags?: string[];
  /** Additional metadata */
  metadata?: Partial<MediaMetadata>;
}

/**
 * Update media response
 */
export interface UpdateMediaResponse {
  /** Updated media */
  media: Media;
  /** Success message */
  message: string;
}

/**
 * Media summary for listings
 */
export interface MediaSummary {
  /** Media ID */
  id: string;
  /** Original filename */
  originalName: string;
  /** Media type */
  type: MediaType;
  /** Public URL */
  url: string;
  /** Thumbnail URL */
  thumbnailUrl: string | null;
  /** File size */
  size: number;
  /** Creation date */
  createdAt: Date;
}

// -----------------------------------------------------------------------------
// Processing Types
// -----------------------------------------------------------------------------

/**
 * Image processing options
 */
export interface ImageProcessingOptions {
  /** Resize to specific width */
  width?: number;
  /** Resize to specific height */
  height?: number;
  /** Resize mode */
  fit?: 'cover' | 'contain' | 'fill' | 'inside' | 'outside';
  /** Output format */
  format?: 'jpeg' | 'png' | 'webp' | 'avif';
  /** Quality (1-100) */
  quality?: number;
  /** Generate thumbnails */
  thumbnails?: ThumbnailConfig[];
}

/**
 * Thumbnail configuration
 */
export interface ThumbnailConfig {
  /** Thumbnail name */
  name: string;
  /** Width in pixels */
  width: number;
  /** Height in pixels (optional, maintains aspect ratio) */
  height?: number;
  /** Output format */
  format?: 'jpeg' | 'png' | 'webp';
  /** Quality */
  quality?: number;
}

/**
 * Processing result
 */
export interface ProcessingResult {
  /** Processed file URL */
  url: string;
  /** New file size */
  size: number;
  /** Dimensions */
  dimensions: ImageDimensions;
  /** Generated thumbnails */
  thumbnails?: MediaVariant[];
  /** Processing time in ms */
  processingTime: number;
}

// -----------------------------------------------------------------------------
// Query/Filter Types
// -----------------------------------------------------------------------------

/**
 * Media list query filters
 */
export interface MediaListFilters {
  /** Filter by media type */
  type?: MediaType;
  /** Filter by MIME type (e.g., 'image/jpeg') */
  mimeType?: string;
  /** Search by filename or alt text */
  search?: string;
  /** Filter by creation date range */
  createdAfter?: Date;
  createdBefore?: Date;
  /** Include soft-deleted */
  includeDeleted?: boolean;
  /** Filter by tags */
  tags?: string[];
}

/**
 * Media list query params
 */
export interface MediaListParams extends MediaListFilters {
  /** Page number (1-indexed) */
  page?: number;
  /** Items per page */
  perPage?: number;
  /** Sort field */
  sortBy?: 'createdAt' | 'originalName' | 'size' | 'type';
  /** Sort direction */
  sortOrder?: 'asc' | 'desc';
}

// -----------------------------------------------------------------------------
// Event Payload Types
// -----------------------------------------------------------------------------

/**
 * Media uploaded event payload
 */
export interface MediaUploadedEvent {
  /** Media ID */
  mediaId: string;
  /** Organization ID */
  organizationId: string;
  /** Original filename */
  originalName: string;
  /** Media type */
  type: MediaType;
  /** File size */
  size: number;
  /** URL */
  url: string;
  /** User who uploaded */
  uploadedBy?: string;
  /** Event timestamp */
  timestamp: string;
}

/**
 * Media deleted event payload
 */
export interface MediaDeletedEvent {
  /** Media ID */
  mediaId: string;
  /** Organization ID */
  organizationId: string;
  /** Original filename */
  originalName: string;
  /** User who deleted */
  deletedBy?: string;
  /** Event timestamp */
  timestamp: string;
}

/**
 * Media processed event payload
 */
export interface MediaProcessedEvent {
  /** Media ID */
  mediaId: string;
  /** Organization ID */
  organizationId: string;
  /** Processing result */
  result: ProcessingResult;
  /** Event timestamp */
  timestamp: string;
}

/**
 * Thumbnail created event payload
 */
export interface ThumbnailCreatedEvent {
  /** Media ID */
  mediaId: string;
  /** Organization ID */
  organizationId: string;
  /** Thumbnail URL */
  thumbnailUrl: string;
  /** Thumbnail dimensions */
  dimensions: ImageDimensions;
  /** Event timestamp */
  timestamp: string;
}

// -----------------------------------------------------------------------------
// Hook Context Types
// -----------------------------------------------------------------------------

/**
 * Before upload hook context
 */
export interface BeforeUploadContext {
  /** Upload request data */
  data: UploadMediaRequest;
  /** Organization ID */
  organizationId: string;
  /** User ID */
  userId?: string;
}

/**
 * After upload hook context
 */
export interface AfterUploadContext {
  /** Uploaded media */
  media: Media;
  /** User ID */
  userId?: string;
}

/**
 * Before delete hook context
 */
export interface BeforeDeleteContext {
  /** Media to delete */
  media: Media;
  /** User ID */
  userId?: string;
}

/**
 * After delete hook context
 */
export interface AfterDeleteContext {
  /** Deleted media ID */
  mediaId: string;
  /** Organization ID */
  organizationId: string;
  /** User ID */
  userId?: string;
}

// -----------------------------------------------------------------------------
// Module Settings Types
// -----------------------------------------------------------------------------

/**
 * Media module settings
 */
export interface MediaModuleSettings {
  /** Maximum file size in bytes */
  maxFileSize: number;
  /** Allowed MIME types */
  allowedMimeTypes: string[];
  /** Thumbnail size configurations */
  thumbnailSizes: {
    small: number;
    medium: number;
    large: number;
  };
  /** Storage provider (local, s3, cdn) */
  storageProvider: 'local' | 's3' | 'cdn';
  /** CDN enabled */
  cdnEnabled: boolean;
  /** Auto-optimize images */
  autoOptimize: boolean;
}

// -----------------------------------------------------------------------------
// Storage Types
// -----------------------------------------------------------------------------

/**
 * Storage configuration
 */
export interface StorageConfig {
  /** Storage provider */
  provider: MediaStorage;
  /** Base path for storage */
  basePath: string;
  /** Public URL prefix */
  publicUrl: string;
  /** S3-specific config (if applicable) */
  s3?: S3Config;
}

/**
 * S3 configuration
 */
export interface S3Config {
  /** Bucket name */
  bucket: string;
  /** AWS region */
  region: string;
  /** Access key ID */
  accessKeyId?: string;
  /** Secret access key */
  secretAccessKey?: string;
  /** Endpoint (for S3-compatible services) */
  endpoint?: string;
}

// -----------------------------------------------------------------------------
// Type Guards
// -----------------------------------------------------------------------------

/**
 * Type guard to check if an object is a valid Media
 */
export function isMedia(obj: unknown): obj is Media {
  return (
    typeof obj === 'object' &&
    obj !== null &&
    'id' in obj &&
    'organizationId' in obj &&
    'filename' in obj &&
    'url' in obj &&
    'type' in obj
  );
}

/**
 * Type guard to check if a MIME type is an image
 */
export function isImageMimeType(mimeType: string): boolean {
  return mimeType.startsWith('image/');
}

/**
 * Type guard to check if a MIME type is a video
 */
export function isVideoMimeType(mimeType: string): boolean {
  return mimeType.startsWith('video/');
}

/**
 * Type guard to check if a MIME type is a document
 */
export function isDocumentMimeType(mimeType: string): boolean {
  return (
    mimeType.startsWith('application/pdf') ||
    mimeType.startsWith('application/msword') ||
    mimeType.startsWith('application/vnd.')
  );
}
